function series() {
  var out = []
  var v = 2200
  for (var i = 0; i < 60; i++) {
    v += Math.sin(i / 4) * 55 + i * 5 - 6
    out.push([i, Math.round(v)])
  }
  return out
}

var options = {
  series: [{ name: 'Revenue', data: series() }],
  chart: {
    id: 'ctxmenu',
    type: 'line',
    height: 400,
    fontFamily: 'Helvetica, Arial, sans-serif',
    animations: { enabled: false },
    toolbar: { show: false },
    zoom: { enabled: true, type: 'x' },
    contextMenu: {
      enabled: true,
      line: { text: 'Event', strokeDashArray: 5, color: '#7c3aed' },
      items: [
        'annotate',
        'xline',
        'yline',
        'measure',
        {
          id: 'copyValue',
          label: 'Copy value',
          onClick: function (chart, ctx) {
            var msg = 'x=' + Math.round(ctx.x) + ', y=' + Math.round(ctx.y)
            var readout = document.getElementById('cm-readout')
            if (readout) readout.textContent = 'Copied ' + msg
            if (navigator.clipboard)
              navigator.clipboard.writeText(msg).catch(function () {})
          },
        },
      ],
    },
    measure: { enabled: true },
    ink: { enabled: true },
  },
  stroke: { width: 2, curve: 'smooth' },
  colors: ['#2563eb'],
  dataLabels: { enabled: false },
  title: {
    text: 'Revenue (right-click to add notes or measure)',
    align: 'left',
  },
  xaxis: { type: 'numeric', title: { text: 'Session' } },
  yaxis: { title: { text: 'Revenue' }, decimalsInFloat: 0 },
}

var chart = new ApexCharts(document.querySelector('#chart'), options)
chart.render()

var readout = document.getElementById('cm-readout')
chart.addEventListener('measured', function (c, o) {
  readout.textContent =
    'Measured: dy=' +
    Number(o.dy).toFixed(0) +
    ' (' +
    (o.percentChange >= 0 ? '+' : '') +
    Number(o.percentChange).toFixed(1) +
    '%)'
})
chart.addEventListener('annotationCreated', function (c, o) {
  var kind =
    o && o.type === 'xaxis'
      ? 'Dashed line'
      : o && o.type === 'yaxis'
        ? 'Level line'
        : 'Note'
  readout.textContent =
    kind +
    ' added. Type to rename it; the floating card restyles or deletes it. Drag to move.'
})

#chart {
  max-width: 820px;
  margin: 12px auto;
}
.cm-panel {
  max-width: 820px;
  margin: 12px auto;
  font-family: Helvetica, Arial, sans-serif;
}
.cm-note {
  background: #eef6ff;
  border-left: 3px solid #2563eb;
  padding: 11px 15px;
  font-size: 13px;
  color: #234;
  border-radius: 2px;
  line-height: 1.6;
  margin: 12px 6px;
}
.cm-note code {
  background: #dbeafe;
  padding: 1px 5px;
  border-radius: 3px;
}
.cm-readout {
  font-family: monospace;
  font-size: 13px;
  color: #445;
  margin: 6px 6px 0;
}
